mapper.sql:
SELECT CTKEY, OWKEY, OBHDYEAR, OBHDMONTH, NULL AS OBHDDAY, SUM(INITORDCNT) AS INITORDCNT, SUM(INITWBLCNT) AS INITWBLCNT, SUM(INITSKU) AS INITSKU, SUM(INITQTY) AS INITQTY, SUM(INITAMT) AS INITAMT, SUM(CNFRMORDCNT) AS CNFRMORDCNT, SUM(CNFRMWBLCNT) AS CNFRMWBLCNT, SUM(CNFRMSKU) AS CNFRMSKU, SUM(CNFRMQTY) AS CNFRMQTY, SUM(CNFRMAMT) AS CNFRMAMT, SUM(CNFRMQTYDW) AS CNFRMQTYDW, SUM(CNFRMQTYRW) AS CNFRMQTYRW, SUM(CNFRMQTYPW) AS CNFRMQTYPW, SUM(CNFRMQTYUW) AS CNFRMQTYUW, SUM(CNFRMQTYET) AS CNFRMQTYET, SUM(CNFRMQTYDAY) AS CNFRMQTYDAY, SUM(CNFRMQTYDWDAY) AS CNFRMQTYDWDAY, SUM(CNFRMQTYRWDAY) AS CNFRMQTYRWDAY, SUM(CNFRMQTYPWDAY) AS CNFRMQTYPWDAY, SUM(CNFRMQTYUWDAY) AS CNFRMQTYUWDAY, SUM(CNFRMQTYETDAY) AS CNFRMQTYETDAY, SUM(CNFRMQTYNGT) AS CNFRMQTYNGT, SUM(CNFRMQTYDWNGT) AS CNFRMQTYDWNGT, SUM(CNFRMQTYRWNGT) AS CNFRMQTYRWNGT, SUM(CNFRMQTYPWNGT) AS CNFRMQTYPWNGT, SUM(CNFRMQTYUWNGT) AS CNFRMQTYUWNGT, SUM(CNFRMQTYETNGT) AS CNFRMQTYETNGT, ROUND(AVG(CNFRMSKUAVG), 2) AS CNFRMSKUAVG, ROUND(AVG(CNFRMQTYAVG), 2) AS CNFRMQTYAVG, ROUND(AVG(CNFRMAMTAVG), 2) AS CNFRMAMTAVG FROM (
SELECT A.CTKEY, A.OWKEY, SUBSTR(A.OBHDDAY, 0, 4) AS OBHDYEAR, SUBSTR(A.OBHDDAY, 5, 2) AS OBHDMONTH, A.OBHDDAY, TO_CHAR(TO_DATE(A.OBHDDAY, 'YYYYMMDD'), 'DY') || '요일' AS OBHDWKDAY, B.INITORDCNT, C.INITWBLCNT, A.INITSKU, A.INITQTY, A.INITAMT, B.CNFRMORDCNT, C.CNFRMWBLCNT, A.CNFRMSKU, A.CNFRMQTY, A.CNFRMAMT, A.CNFRMQTYDW, A.CNFRMQTYRW, A.CNFRMQTYPW, A.CNFRMQTYUW, A.CNFRMQTYET, A.CNFRMQTYDWDAY + A.CNFRMQTYRWDAY + A.CNFRMQTYPWDAY + A.CNFRMQTYUWDAY + A.CNFRMQTYETDAY AS CNFRMQTYDAY, A.CNFRMQTYDWDAY, A.CNFRMQTYRWDAY, A.CNFRMQTYPWDAY, A.CNFRMQTYUWDAY, A.CNFRMQTYETDAY, A.CNFRMQTYDWNGT + A.CNFRMQTYRWNGT + A.CNFRMQTYPWNGT + A.CNFRMQTYUWNGT + A.CNFRMQTYETNGT AS CNFRMQTYNGT, A.CNFRMQTYDWNGT, A.CNFRMQTYRWNGT, A.CNFRMQTYPWNGT, A.CNFRMQTYUWNGT, A.CNFRMQTYETNGT, ROUND(A.CNFRMSKUAVG) AS CNFRMSKUAVG, ROUND(A.CNFRMQTYAVG) AS CNFRMQTYAVG, ROUND(A.CNFRMAMTAVG) AS CNFRMAMTAVG FROM ( SELECT A.CTKEY ,A.OWKEY ,A.OBHDDAY -- 출고희망일자 ,SUM(INITSKU) AS INITSKU ,SUM(INITQTY) AS INITQTY ,SUM(INITAMT) AS INITAMT ,SUM(CNFRMSKU) AS CNFRMSKU ,SUM(CNFRMQTY) AS CNFRMQTY ,SUM(CNFRMAMT) AS CNFRMAMT ,SUM(A.CNFRMQTYDW) AS CNFRMQTYDW ,SUM(A.CNFRMQTYRW) AS CNFRMQTYRW ,SUM(A.CNFRMQTYPW) AS CNFRMQTYPW ,SUM(A.CNFRMQTYUW) AS CNFRMQTYUW ,SUM(A.CNFRMQTYET) AS CNFRMQTYET ,SUM(A.CNFRMQTYDWDAY) AS CNFRMQTYDWDAY ,SUM(A.CNFRMQTYRWDAY) AS CNFRMQTYRWDAY ,SUM(A.CNFRMQTYPWDAY) AS CNFRMQTYPWDAY ,SUM(A.CNFRMQTYUWDAY) AS CNFRMQTYUWDAY ,SUM(A.CNFRMQTYETDAY) AS CNFRMQTYETDAY ,SUM(A.CNFRMQTYDWNGT) AS CNFRMQTYDWNGT ,SUM(A.CNFRMQTYRWNGT) AS CNFRMQTYRWNGT ,SUM(A.CNFRMQTYPWNGT) AS CNFRMQTYPWNGT ,SUM(A.CNFRMQTYUWNGT) AS CNFRMQTYUWNGT ,SUM(A.CNFRMQTYETNGT) AS CNFRMQTYETNGT ,AVG(A.CNFRMSKU) AS CNFRMSKUAVG ,AVG(A.CNFRMQTY) AS CNFRMQTYAVG ,AVG(A.CNFRMAMT) AS CNFRMAMTAVG FROM ( SELECT OH.CTKEY /*센터코드*/ , OH.OWKEY /*화주코드*/ -- , OH.OBREQDATE /*주문지시일시*/ -- , SUBSTR(OH.OBHDDAY, 0, 4) AS OBHDYEAR /*출고희망연도*/ -- , SUBSTR(OH.OBHDDAY, 5, 2) AS OBHDMONTH /*출고희망월*/ , SUBSTR(OH.OBHDDAY, 0, 8) AS OBHDDAY /*출고희망일자*/ --, TO_CHAR(TO_DATE(SUBSTR(OH.OBHDDAY, 0, 8), 'YYYYMMDD'), 'DY') || '요일' AS OBHDWKDAY /*출고희망요일*/ , OH.OBORDKEY /*오더코드*/ -- , OH.WBLNO /*송장번호*/ , COUNT(*) AS INITSKU /*주문량-SKU*/ , SUM(OD.INITQTY) AS INITQTY /*주문량-EA*/ , SUM(COALESCE(OD.INITQTY, 0) * COALESCE(IC.SLPRC, 0)) AS INITAMT /*주문량-금액*/ , SUM(CASE WHEN OH.OBSTATUSCD IN('65', '70') THEN 1 ELSE 0 END) AS CNFRMSKU /*출고량-SKU*/ , SUM(OD.CNFRMQTY) AS CNFRMQTY /*출고량-EA*/ , SUM(COALESCE(OD.CNFRMQTY, 0) * COALESCE(IC.SLPRC, 0)) AS CNFRMAMT /*출고량-금액*/ , SUM(CASE WHEN OH.WKTYPECD = 'DW' THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYDW /*출고건수-DAS*/ , SUM(CASE WHEN OH.WKTYPECD = 'RW' THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYRW /*출고건수-로봇*/ , SUM(CASE WHEN OH.WKTYPECD = 'PW' THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYPW /*출고건수-덕용*/ , SUM(CASE WHEN OH.WKTYPECD = 'UW' THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYUW /*출고건수-단포*/ , SUM(CASE WHEN OH.WKTYPECD NOT IN ('DW', 'RW', 'PW', 'UW') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYET /*출고건수-수작업*/ , SUM(CASE WHEN OH.WKTYPECD = 'DW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYDWDAY /*주간출고건수-DAS*/ , SUM(CASE WHEN OH.WKTYPECD = 'RW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYRWDAY /*주간출고건수-로봇*/ , SUM(CASE WHEN OH.WKTYPECD = 'PW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYPWDAY /*주간출고건수-덕용*/ , SUM(CASE WHEN OH.WKTYPECD = 'UW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYUWDAY /*주간출고건수-수작업*/ , SUM(CASE WHEN OH.WKTYPECD NOT IN ('DW', 'RW', 'PW', 'UW') AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYETDAY /*주간출고건수-단포*/ , SUM(CASE WHEN OH.WKTYPECD = 'DW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) NOT BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYDWNGT /*야간출고건수-DAS*/ , SUM(CASE WHEN OH.WKTYPECD = 'RW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) NOT BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYRWNGT /*야간출고건수-로봇*/ , SUM(CASE WHEN OH.WKTYPECD = 'PW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) NOT BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYPWNGT /*야간출고건수-덕용*/ , SUM(CASE WHEN OH.WKTYPECD = 'UW' AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) NOT BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYUWNGT /*야간출고건수-단포*/ , SUM(CASE WHEN OH.WKTYPECD NOT IN ('DW', 'RW', 'PW', 'UW') AND (SUBSTR(OH.OBCNFRMDATE, 9, 6) NOT BETWEEN '090000' AND '205959') THEN OD.CNFRMQTY ELSE 0 END) AS CNFRMQTYETNGT /*주간출고건수-수작업*/ FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_CT CT ON OH.CTKEY = CT.CTKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY WHERE 1=1
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.OBHDDAY BETWEEN #{wrkStartDate} || '000000' AND #{wrkEndDate} || '235959'
GROUP BY OH.CTKEY /*센터코드*/ , OH.OWKEY /*화주코드*/ , OH.OBHDDAY /*출고희망일자*/ , OH.OBORDKEY ) A GROUP BY A.CTKEY /*센터코드*/ , A.OWKEY /*화주코드*/ , A.OBHDDAY /*출고희망일자*/ ) A INNER JOIN ( SELECT CTKEY, OWKEY, OBHDDAY, SUM(FLAG1) INITORDCNT, /*주문건수-주문단위*/ SUM(FLAG2) CNFRMORDCNT /*출고건수-주문단위*/ FROM ( SELECT OH.CTKEY, OH.OWKEY, SUBSTR(OH.OBHDDAY, 0, 8) AS OBHDDAY, /*출고희망일자*/ OH.OBORDKEY, 1 AS FLAG1, /*주문수-SKU*/ CASE WHEN SUM(CASE WHEN OH.OBSTATUSCD IN ('65', '70') THEN 1 ELSE 0 END) = SUM(1) THEN 1 ELSE 0 END AS FLAG2 /*주문수-SKU*/ FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_MST_CT CT ON OH.CTKEY = CT.CTKEY
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.OBHDDAY BETWEEN #{wrkStartDate} || '000000' AND #{wrkEndDate} || '235959'
GROUP BY OH.CTKEY, OH.OWKEY, SUBSTR(OH.OBHDDAY, 0, 8), OH.OBORDKEY ) GROUP BY CTKEY, OWKEY, OBHDDAY ) B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDDAY = B.OBHDDAY INNER JOIN ( SELECT CTKEY, OWKEY, OBHDDAY, SUM(FLAG1) INITWBLCNT, /*주문건수-주문단위*/ SUM(FLAG2) CNFRMWBLCNT /*출고건수-주문단위*/ FROM ( SELECT OH.CTKEY, OH.OWKEY, SUBSTR(OH.OBHDDAY, 0, 8) AS OBHDDAY, /*출고희망일자*/ OH.WBLNO, 1 AS FLAG1, /*주문수-SKU*/ CASE WHEN SUM(CASE WHEN OH.OBSTATUSCD IN ('65', '70') THEN 1 ELSE 0 END) = SUM(1) THEN 1 ELSE 0 END AS FLAG2 /*주문수-SKU*/ FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_MST_CT CT ON OH.CTKEY = CT.CTKEY WHERE 1=1
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.OBHDDAY BETWEEN #{wrkStartDate} || '000000' AND #{wrkEndDate} || '235959'
GROUP BY OH.CTKEY, OH.OWKEY, SUBSTR(OH.OBHDDAY, 0, 8), OH.WBLNO ) GROUP BY CTKEY, OWKEY, OBHDDAY ) C ON A.CTKEY = C.CTKEY AND B.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND B.OWKEY = C.OWKEY AND A.OBHDDAY = C.OBHDDAY AND B.OBHDDAY = C.OBHDDAY ORDER BY A.OBHDDAY
) GROUP BY CTKEY, OWKEY, OBHDYEAR, OBHDMONTH

