mapper.sql:
WITH WH_BASE AS ( SELECT * FROM TWORK_INFO_WA_HD WH WHERE 1=1
AND #{SEARCH_CONDITION}
), A AS ( SELECT /* hint: LEADING(WH PH OH OD PD TPD) USE_HASH(OH OD PH PD TPD) */ WH.OWKEY, WH.CTKEY, WH.WAHDDAY, WH.WAHDKEY, WH.PIHDKEY, PH.PIHDNM, WH.WKTYPECD, WH.WARND, WH.WAHDNM, WH.WAWKSTATUSCD, COUNT(DISTINCT OH.OBHDKEY1) AS EXOBORDCNT, COUNT(DISTINCT TPD.LCKEY) AS EXOBCELLCNT, COUNT(DISTINCT OD.ICKEY) AS EXOBSKU, SUM(OD.EXPCTQTY) AS EXOBQTY, SUM(CASE WHEN OD.ROBSORTERICYN = 'Y' THEN OD.EXPCTQTY ELSE 0 END) AS REXOBQTY, SUM(CASE WHEN OD.ROBSORTERICYN = 'N' THEN OD.EXPCTQTY ELSE 0 END) AS DEXOBQTY, COUNT(DISTINCT CASE WHEN TPD.PKCNFRMDATE IS NOT NULL THEN TPD.LCKEY END) AS PROCCELLCNT, COUNT(DISTINCT CASE WHEN (OH.PCKGDATE IS NOT NULL OR OH.OBHDKEY2 IS NOT NULL) AND OH.WKTYPECD != 'RW' THEN OH.OBHDKEY1 END) AS DPAKOBORDCNT, COUNT(DISTINCT CASE WHEN (OH.PCKGDATE IS NOT NULL OR OH.OBHDKEY2 IS NOT NULL) AND OH.WKTYPECD = 'RW' THEN OH.OBHDKEY1 END) AS RPAKOBORDCNT FROM WH_BASE WH LEFT JOIN TWORK_INFO_PI_HD PH ON WH.OWKEY = PH.OWKEY AND WH.CTKEY = PH.CTKEY AND WH.PIHDKEY = PH.PIHDKEY LEFT JOIN ( SELECT OH.OWKEY, OH.CTKEY, OH.WAHDKEY, OH.WKTYPECD, OH.OBHDKEY AS OBHDKEY1, OH.PCKGDATE AS PCKGDATE, NH.OBHDKEY AS OBHDKEY2 FROM TWORK_INFO_OB_HD OH LEFT OUTER JOIN TWORK_INFO_OB_NIS_HD NH ON OH.OWKEY = NH.OWKEY AND OH.CTKEY = NH.CTKEY AND OH.OBHDKEY = NH.OBHDKEY ) OH ON WH.OWKEY = OH.OWKEY AND WH.CTKEY = OH.CTKEY AND WH.WAHDKEY = OH.WAHDKEY LEFT JOIN TWORK_INFO_OB_DT OD ON OH.OWKEY = OD.OWKEY AND OH.CTKEY = OD.CTKEY AND OH.OBHDKEY1 = OD.OBHDKEY LEFT JOIN TWORK_INFO_PI_DT PD ON OD.OWKEY = PD.OWKEY AND OD.CTKEY = PD.CTKEY AND OD.OBHDKEY = PD.OBHDKEY AND OD.OBDTKEY = PD.OBDTKEY AND OD.ICKEY = PD.ICKEY LEFT JOIN TWORK_INFO_PI_TOT_DT TPD ON TPD.OWKEY = PD.OWKEY AND TPD.CTKEY = PD.CTKEY AND TPD.PIHDKEY = PD.PIHDKEY AND TPD.ICKEY = PD.ICKEY AND TPD.LCKEY = PD.LCKEY AND TPD.IVATKEY = PD.IVATKEY GROUP BY WH.OWKEY, WH.CTKEY, WH.WAHDDAY, WH.WAHDKEY, WH.PIHDKEY, PH.PIHDNM, WH.WKTYPECD, WH.WARND, WH.WAHDNM, WH.WAWKSTATUSCD ), B AS ( SELECT X.OWKEY, X.CTKEY, X.WAHDKEY, SUM(X.SCLASSIFSQTY) AS SCLASSIFSQTY, SUM(X.RCLASSIFSQTY) AS RCLASSIFSQTY, SUM(X.DCLASSIFSQTY) AS DCLASSIFSQTY FROM ( SELECT A.OWKEY, A.CTKEY, A.WAHDKEY, SUM(C.QTY) AS SCLASSIFSQTY, 0 AS RCLASSIFSQTY, 0 AS DCLASSIFSQTY FROM TWIF_DAS_PRCSRSLT_WA A JOIN TWIF_DAS_PRCSRSLT_ORDER B ON A.OWKEY=B.OWKEY AND A.CTKEY=B.CTKEY AND A.WASEQ=B.WASEQ JOIN TWIF_DAS_PRCSRSLT_IC C ON B.OWKEY=C.OWKEY AND B.CTKEY=C.CTKEY AND B.WASEQ=C.WASEQ AND B.ORDERSEQ=C.ORDERSEQ WHERE A.CTKEY = '09' AND A.DASDIV='3' AND A.IFTYPE='R' AND A.IFSTATUS='90' GROUP BY A.OWKEY, A.CTKEY, A.WAHDKEY UNION ALL SELECT A.OWKEY, A.CTKEY, A.WAHDKEY, 0, SUM(C.QTY), 0 FROM TWIF_ROBDAS_PRCSRSLT_WA A JOIN TWIF_ROBDAS_PRCSRSLT_ORDER B ON A.OWKEY=B.OWKEY AND A.CTKEY=B.CTKEY AND A.WASEQ=B.WASEQ JOIN TWIF_ROBDAS_PRCSRSLT_IC C ON B.OWKEY=C.OWKEY AND B.CTKEY=C.CTKEY AND B.WASEQ=C.WASEQ AND B.ORDERSEQ=C.ORDERSEQ WHERE A.CTKEY = '09' AND A.IFTYPE='R' AND A.IFSTATUS='90' GROUP BY A.OWKEY, A.CTKEY, A.WAHDKEY UNION ALL SELECT A.OWKEY, A.CTKEY, A.WAHDKEY, 0, 0, SUM(C.QTY) FROM TWIF_ROBDAS_RSLTXNIS_WA A JOIN TWIF_ROBDAS_RSLTXNIS_ORDER B ON A.OWKEY=B.OWKEY AND A.CTKEY=B.CTKEY AND A.WASEQ=B.WASEQ JOIN TWIF_ROBDAS_RSLTXNIS_IC C ON B.OWKEY=C.OWKEY AND B.CTKEY=C.CTKEY AND B.WASEQ=C.WASEQ AND B.ORDERSEQ=C.ORDERSEQ WHERE A.CTKEY = '09' AND A.IFTYPE='R' AND A.IFSTATUS='90' AND ROBDASRSLTTYPE = '1' GROUP BY A.OWKEY, A.CTKEY, A.WAHDKEY ) X GROUP BY X.OWKEY, X.CTKEY, X.WAHDKEY ), C AS ( SELECT A.OWKEY, A.CTKEY, A.WAHDKEY, SUM(C.QTY) AS MCLASSIFSQTY FROM TWIF_DAS_PRCSRSLT_WA A JOIN TWIF_DAS_PRCSRSLT_ORDER B ON A.OWKEY=B.OWKEY AND A.CTKEY=B.CTKEY AND A.WASEQ=B.WASEQ JOIN TWIF_DAS_PRCSRSLT_IC C ON B.OWKEY=C.OWKEY AND B.CTKEY=C.CTKEY AND B.WASEQ=C.WASEQ AND B.ORDERSEQ=C.ORDERSEQ WHERE A.CTKEY = '09' AND A.DASDIV='2' AND A.IFTYPE='R' AND A.IFSTATUS='90' GROUP BY A.OWKEY, A.CTKEY, A.WAHDKEY ) SELECT A.OWKEY, A.CTKEY, A.WAHDDAY, A.WAHDKEY, A.PIHDKEY, A.PIHDNM, A.WKTYPECD, A.WARND, A.WAHDNM, A.WAWKSTATUSCD, /*출고예정정보 > 주문건수 / 피킹셀수 / SKU / EA*/ A.EXOBORDCNT, A.EXOBCELLCNT, A.EXOBSKU, A.EXOBQTY, /*총량피킹 (CELL) > 완료 / 잔여 / 진척율 */ A.PROCCELLCNT, GREATEST(COALESCE(A.EXOBCELLCNT - A.PROCCELLCNT, 0), 0) AS RMCELLCNT, ROUND(A.PROCCELLCNT / NULLIF(A.EXOBCELLCNT, 0) * 100, 1) AS PROCCELLPCT, /*중분류 (EA) > 완료 / 잔여 / 진척율 */ CASE WHEN A.WKTYPECD = 'DW' THEN COALESCE(C.MCLASSIFSQTY, 0) ELSE 0 END AS MCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'RW' THEN GREATEST(A.EXOBQTY - COALESCE(C.MCLASSIFSQTY, 0), 0) ELSE 0 END AS RMMCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'DW' THEN ROUND(COALESCE(C.MCLASSIFSQTY, 0) / NULLIF(A.EXOBQTY, 0) * 100, 1) ELSE 0 END AS PROCMCLASSIFSPCT, /*소분류 (EA) > 완료 / 잔여 / 진척율 */ CASE WHEN A.WKTYPECD = 'DW' THEN COALESCE(B.SCLASSIFSQTY, 0) ELSE 0 END AS SCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'DW' THEN GREATEST(A.EXOBQTY - COALESCE(B.SCLASSIFSQTY, 0), 0) ELSE 0 END AS RMSCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'DW' THEN ROUND(COALESCE(B.SCLASSIFSQTY, 0) / NULLIF(A.EXOBQTY, 0) * 100, 1) ELSE 0 END AS PROCSCLASSIFSPCT, /*DAS검수 (건수) > 완료 / 잔여 / 진척율 */ CASE WHEN A.WKTYPECD != 'RW' THEN A.DPAKOBORDCNT ELSE 0 END AS DPAKOBORDCNT, CASE WHEN A.WKTYPECD != 'RW' THEN GREATEST(COALESCE(A.EXOBORDCNT - A.DPAKOBORDCNT, 0), 0) ELSE 0 END AS RMDPAKOBORDCNT, CASE WHEN A.WKTYPECD != 'RW' THEN ROUND(A.DPAKOBORDCNT / NULLIF(A.EXOBORDCNT, 0) * 100, 1) ELSE 0 END AS PROCDPAKOBORDPCT, /*로봇투입 (EA) > 완료 / 잔여 / 진척율 */ CASE WHEN A.WKTYPECD = 'RW' THEN COALESCE(B.RCLASSIFSQTY, 0) ELSE 0 END AS RCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'RW' THEN GREATEST(A.REXOBQTY - COALESCE(B.RCLASSIFSQTY, 0), 0) ELSE 0 END AS RMRCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'RW' THEN ROUND(COALESCE(B.RCLASSIFSQTY, 0) / NULLIF(A.REXOBQTY, 0) * 100, 1) ELSE 0 END AS PROCRCLASSIFSPCT, /*로봇검수 (건수) > 완료 / 잔여 / 진척율 */ CASE WHEN A.WKTYPECD = 'RW' THEN A.RPAKOBORDCNT ELSE 0 END AS RPAKOBORDCNT, CASE WHEN A.WKTYPECD = 'RW' THEN GREATEST(COALESCE(A.EXOBORDCNT - A.RPAKOBORDCNT, 0), 0) ELSE 0 END AS RMRPAKOBORDCNT, CASE WHEN A.WKTYPECD = 'RW' THEN ROUND(A.RPAKOBORDCNT / NULLIF(A.EXOBORDCNT, 0) * 100, 1) ELSE 0 END AS PROCRPAKOBORDPCT, /*로봇이형물 (EA) > 완료 / 잔여 / 진척율 */ CASE WHEN A.WKTYPECD = 'RW' THEN COALESCE(B.DCLASSIFSQTY, 0) ELSE 0 END AS DCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'RW' THEN GREATEST(A.DEXOBQTY - COALESCE(B.DCLASSIFSQTY, 0), 0) ELSE 0 END AS RMDCLASSIFSQTY, CASE WHEN A.WKTYPECD = 'RW' THEN ROUND(COALESCE(B.DCLASSIFSQTY, 0) / NULLIF(A.DEXOBQTY, 0) * 100, 1) ELSE 0 END AS PROCDCLASSIFSPCT FROM A LEFT JOIN B ON A.OWKEY=B.OWKEY AND A.CTKEY=B.CTKEY AND A.WAHDKEY=B.WAHDKEY LEFT JOIN C ON A.OWKEY=C.OWKEY AND A.CTKEY=C.CTKEY AND A.WAHDKEY=C.WAHDKEY ORDER BY A.WAHDKEY

