mapper.sql:
WITH A AS ( SELECT PD.OWKEY, PD.CTKEY, PD.PIHDKEY, PD.LCKEY, PD.IVATKEY, PD.ICKEY, SUM(CASE WHEN WH.WKTYPECD = 'RW' AND PD.ROBSORTERICYN = 'Y' THEN PD.EXPCTQTY ELSE 0 END) AS EXRBQTY, SUM(CASE WHEN WH.WKTYPECD = 'RW' AND PD.ROBSORTERICYN = 'N' THEN PD.EXPCTQTY ELSE 0 END) AS EXDFQTY, SUM(CASE WHEN WH.WKTYPECD != 'RW' THEN PD.EXPCTQTY ELSE 0 END) AS EXDASQTY FROM TWORK_INFO_WA_HD WH INNER JOIN TWORK_INFO_WA_DT WD ON WH.OWKEY = WD.OWKEY AND WH.CTKEY = WD.CTKEY AND WH.WAHDKEY = WD.WAHDKEY INNER JOIN TWORK_INFO_PI_DT PD ON PD.OWKEY = WD.OWKEY AND PD.CTKEY = WD.CTKEY AND PD.OBHDKEY = WD.OBHDKEY AND PD.PIHDKEY = WH.PIHDKEY WHERE 1=1
AND WH.OWKEY = #{owkey}
AND WH.CTKEY = #{ctkey}
AND WH.PIHDKEY = #{pihdkey}
GROUP BY PD.OWKEY, PD.CTKEY, PD.PIHDKEY, PD.LCKEY, PD.IVATKEY, PD.ICKEY ), B AS ( SELECT TPD.OWKEY, TPD.CTKEY, TPD.PIHDKEY, TPD.IVATKEY, TPD.LCKEY, TPD.ICKEY, SUM(TPD.EXPCTQTY) AS EXPCTQTY, SUM(TPD.CNFRMQTY) AS CNFRMQTY, TO_DATE(MIN(TPD.PKCNFRMDATE), 'YYYYMMDDHH24MISS') AS STARTDATE FROM TWORK_INFO_PI_TOT_DT TPD WHERE 1=1
AND TPD.OWKEY = #{owkey}
AND TPD.CTKEY = #{ctkey}
AND TPD.PIHDKEY = #{pihdkey}
GROUP BY TPD.OWKEY, TPD.CTKEY, TPD.PIHDKEY, TPD.LCKEY, TPD.IVATKEY, TPD.ICKEY ), C AS ( SELECT CTKEY, ZNKEY, ARKEY, TIERNO, COUNT(DISTINCT URKEY) AS USRCNT, TO_DATE(MIN(PKCNFRMDATE), 'YYYYMMDDHH24MISS') AS ENDDATE FROM ( SELECT L.CTKEY, L.ZNKEY, L.ARKEY, L.TIERNO, TPD.PKCNFRMDATE, REPLACE(TPD.PKCNFRMURKEY, 'AD', '') URKEY, RANK() OVER (PARTITION BY REPLACE(TPD.PKCNFRMURKEY, 'AD', '') ORDER BY TPD.PKCNFRMDATE DESC) RNK FROM TWORK_INFO_PI_TOT_DT TPD INNER JOIN TWORK_MST_LC L ON TPD.CTKEY = L.CTKEY AND TPD.LCKEY = L.LCKEY WHERE PKCNFRMURKEY IS NOT NULL
AND TPD.OWKEY = #{owkey}
AND TPD.CTKEY = #{ctkey}
AND TPD.PIHDKEY = #{pihdkey}
GROUP BY L.CTKEY, L.ZNKEY, L.ARKEY, L.TIERNO, PKCNFRMDATE, REPLACE(PKCNFRMURKEY, 'AD', '') ) WHERE RNK = 1 GROUP BY ROLLUP(CTKEY, ZNKEY, ARKEY, TIERNO) HAVING (ZNKEY = 'H' AND ARKEY IS NOT NULL AND TIERNO IS NULL) OR (ZNKEY = 'P' AND ARKEY IS NOT NULL) ) SELECT /*구역, 단*/ COALESCE(B.ARKEY, A.ARKEY) AS ARKEY ,COALESCE(B.TIERNO, '합계') AS TIERNO ,'합계' AS TIERNO
/*진척현황 > 예정 (CELL, SKU, EA)*/ , EXLCCNT, EXICCNT, EXQTY /*진척현황 > 실적 (CELL, SKU, EA)*/ , EXLCCNT - RMLCCNT AS CFLCCNT, EXICCNT - RMICCNT AS CFICCNT, CFQTY /*진척현황 > 진척율 (CELL, SKU, EA)*/ , CASE WHEN EXLCCNT = 0 THEN 0 ELSE ROUND((EXLCCNT - RMLCCNT) / EXLCCNT * 100, 1) END AS PROCLC , CASE WHEN EXICCNT = 0 THEN 0 ELSE ROUND((EXICCNT - RMICCNT) / EXICCNT * 100, 1) END AS PROCIC , CASE WHEN EXQTY = 0 THEN 0 ELSE ROUND(CFQTY / EXQTY * 100, 1) END AS PROCQTY
/*예정 > 로봇일반 (CELL, SKU, EA)*/ , EXRBLCCNT, EXRBICCNT, EXRBQTY /*예정 > 로봇이형물 (CELL, SKU, EA)*/ , EXDFLCCNT, EXDFICCNT, EXDFQTY /*예정 > DAS (CELL, SKU, EA)*/ , EXDASLCCNT, EXDASICCNT, EXDASQTY /*예정 > 합계 (CELL, SKU, EA)*/ , (EXRBLCCNT + EXDFLCCNT + EXDASLCCNT) EXTOTLCCNT , (EXDFLCCNT + EXDFICCNT + EXDFQTY) EXTOTICCNT , (EXRBQTY + EXDFQTY + EXDASQTY) EXTOTQTY
/*실적 > 로봇일반 (CELL, SKU, EA)*/ , GREATEST(COALESCE(EXRBLCCNT - RMRBLCCNT, 0), 0) AS CFRBLCCNT, GREATEST(COALESCE(EXRBICCNT - RMRBICCNT, 0), 0) AS CFRBICCNT, CFRBQTY /*실적 > 로봇이형물 (CELL, SKU, EA)*/ , GREATEST(COALESCE(EXDFLCCNT - RMDFLCCNT, 0), 0) AS CFDFLCCNT, GREATEST(COALESCE(EXDFICCNT - RMDFICCNT, 0), 0) AS CFDFICCNT, CFDFQTY /*실적 > DAS (CELL, SKU, EA)*/ , GREATEST(COALESCE(EXDASLCCNT - RMDASLCCNT, 0), 0) AS CFDASLCCNT, GREATEST(COALESCE(EXDASICCNT - RMDASICCNT, 0), 0) AS CFDASICCNT, CFDASQTY /*실적 > 합계 (CELL, SKU, EA)*/ , GREATEST(COALESCE(EXRBLCCNT - RMRBLCCNT, 0), 0) + GREATEST(COALESCE(EXDFLCCNT - RMDFLCCNT, 0), 0) + GREATEST(COALESCE(EXDASLCCNT - RMDASLCCNT, 0), 0) AS CFTOTLCCNT , GREATEST(COALESCE(EXRBICCNT - RMRBICCNT, 0), 0) + GREATEST(COALESCE(EXDFICCNT - RMDFICCNT, 0), 0) + GREATEST(COALESCE(EXDASICCNT - RMDASICCNT, 0), 0) AS CFTOTICCNT , CFRBQTY + CFDFQTY + CFDASQTY AS CFTOTQTY , C.usrcnt ,TO_CHAR(A.startdate, 'YYYY-MM-DD HH24:MI:SS') AS startdate ,TO_CHAR(C.enddate, 'YYYY-MM-DD HH24:MI:SS') AS enddate ,LPAD(TRUNC((C.ENDDATE - A.STARTDATE) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((C.ENDDATE - A.STARTDATE) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((C.ENDDATE - A.STARTDATE) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS timediff ,(C.ENDDATE - A.STARTDATE) * 24 * 60 * 60 AS timediff2 FROM ( SELECT L.ARKEY, L.TIERNO, COUNT(DISTINCT A.LCKEY) AS EXLCCNT, COUNT(DISTINCT A.ICKEY) AS EXICCNT, SUM(B.EXPCTQTY) AS EXQTY, COUNT(DISTINCT CASE WHEN B.CNFRMQTY = 0 THEN A.LCKEY END) AS RMLCCNT, COUNT(DISTINCT CASE WHEN B.CNFRMQTY = 0 THEN A.ICKEY END) AS RMICCNT, SUM(B.CNFRMQTY) AS CFQTY, COUNT(DISTINCT CASE WHEN A.EXRBQTY > 0 THEN A.LCKEY END) AS EXRBLCCNT, COUNT(DISTINCT CASE WHEN A.EXRBQTY > 0 THEN A.ICKEY END) AS EXRBICCNT, SUM(A.EXRBQTY) AS EXRBQTY, COUNT(DISTINCT CASE WHEN A.EXDFQTY > 0 THEN A.LCKEY END) AS EXDFLCCNT, COUNT(DISTINCT CASE WHEN A.EXDFQTY > 0 THEN A.ICKEY END) AS EXDFICCNT, SUM(A.EXDFQTY) AS EXDFQTY, COUNT(DISTINCT CASE WHEN A.EXDASQTY > 0 THEN A.LCKEY END) AS EXDASLCCNT, COUNT(DISTINCT CASE WHEN A.EXDASQTY > 0 THEN A.ICKEY END) AS EXDASICCNT, SUM(A.EXDASQTY) AS EXDASQTY, -- 로봇 일반 (미처리 CELL/SKU, 처리EA) COUNT(DISTINCT CASE WHEN B.CNFRMQTY = 0 THEN A.LCKEY END) AS RMRBLCCNT, COUNT(DISTINCT CASE WHEN B.CNFRMQTY = 0 THEN A.ICKEY END) AS RMRBICCNT, SUM(CASE WHEN A.EXRBQTY > B.CNFRMQTY THEN B.CNFRMQTY ELSE A.EXRBQTY END) AS CFRBQTY, -- 로봇 이형물 (미처리 CELL/SKU, 처리EA) COUNT(DISTINCT CASE WHEN B.CNFRMQTY = 0 THEN A.LCKEY END) AS RMDFLCCNT, COUNT(DISTINCT CASE WHEN B.CNFRMQTY = 0 THEN A.ICKEY END) AS RMDFICCNT, SUM(CASE WHEN A.EXDFQTY > B.CNFRMQTY THEN B.CNFRMQTY ELSE A.EXDFQTY END) AS CFDFQTY, -- DAS (미처리 CELL/SKU, 처리EA) COUNT(DISTINCT CASE WHEN B.CNFRMQTY > (CASE WHEN A.EXRBQTY > 0 THEN A.EXRBQTY ELSE A.EXDFQTY END) THEN A.LCKEY END) AS RMDASLCCNT, COUNT(DISTINCT CASE WHEN B.CNFRMQTY > (CASE WHEN A.EXRBQTY > 0 THEN A.EXRBQTY ELSE A.EXDFQTY END) THEN A.ICKEY END) AS RMDASICCNT, SUM( CASE WHEN A.EXDASQTY > 0 AND B.STARTDATE IS NOT NULL THEN CASE WHEN (CASE WHEN A.EXRBQTY > 0 THEN A.EXRBQTY ELSE A.EXDFQTY END) > B.CNFRMQTY THEN 0 ELSE B.CNFRMQTY - (CASE WHEN A.EXRBQTY > 0 THEN A.EXRBQTY ELSE A.EXDFQTY END) END ELSE 0 END ) AS CFDASQTY, MIN(B.STARTDATE) AS startdate FROM A INNER JOIN B ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.PIHDKEY = B.PIHDKEY AND A.IVATKEY = B.IVATKEY AND A.LCKEY = B.LCKEY AND A.ICKEY = B.ICKEY INNER JOIN TWORK_MST_LC L ON B.CTKEY = L.CTKEY AND B.LCKEY = L.LCKEY WHERE 1=1
AND L.ZNKEY = #{znkey}
GROUP BY ROLLUP(L.ZNKEY, L.ARKEY, L.TIERNO) HAVING (L.ZNKEY = 'H' AND L.ARKEY IS NOT NULL AND L.TIERNO IS NULL) OR (L.ZNKEY = 'P' AND L.ARKEY IS NOT NULL) ) A INNER JOIN C ON A.ARKEY = C.ARKEY AND COALESCE(A.TIERNO, '합계') = COALESCE(C.TIERNO, '합계') FULL OUTER JOIN ( SELECT ARKEY ,TIERNO FROM TWORK_MST_LC WHERE ZNKEY IN ('H', 'P') AND LCTYPECD = '90'
AND CTKEY = #{ctkey}
AND ZNKEY = #{znkey}
GROUP BY ARKEY , TIERNO ) B ON A.ARKEY = B.ARKEY
AND A.TIERNO = B.TIERNO
ORDER BY COALESCE(B.ARKEY, A.ARKEY) ,B.TIERNO

