mapper.sql:
WITH BASE AS ( SELECT WH.OWKEY, WH.CTKEY, COALESCE(WL.MDLCLASSIFSTNBARCODE, '로봇 이형물') AS MIDSTN, C.ICKEY, C.EMPNOBRCD, C.QTY, TO_DATE(C.INSERTDATE, 'YYYYMMDDHH24MISS') AS INSERT_DT FROM TWORK_INFO_WA_HD WH JOIN TWIF_DAS_PRCSRSLT_WA A ON A.OWKEY = WH.OWKEY AND A.CTKEY = WH.CTKEY AND A.WAHDKEY = WH.WAHDKEY JOIN TWIF_DAS_PRCSRSLT_ORDER B ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.WASEQ = B.WASEQ JOIN TWIF_DAS_PRCSRSLT_IC C ON B.OWKEY = C.OWKEY AND B.CTKEY = C.CTKEY AND B.WASEQ = C.WASEQ AND B.ORDERSEQ = C.ORDERSEQ LEFT JOIN TWORK_INFO_WA_DAS_STN_LC WL ON B.OWKEY = WL.OWKEY AND B.CTKEY = WL.CTKEY AND B.WAHDKEY = WL.WAHDKEY AND B.DASCELLBRCD = WL.MDLCLASSIFCELLBARCODE WHERE A.DASDIV = '2' AND A.IFTYPE = 'R' AND A.IFSTATUS = '90'
AND WH.OWKEY = #{owkey}
AND WH.CTKEY = #{ctkey}
AND WH.PIHDKEY = #{pihdkey}
), PROC_SUM AS ( SELECT OWKEY, CTKEY, MIDSTN, COUNT(DISTINCT ICKEY) AS CFICCNT, MIN(INSERT_DT) AS START_DT, MAX(INSERT_DT) AS END_DT, SUM(QTY) AS DCLFRMQTY FROM BASE GROUP BY OWKEY, CTKEY, MIDSTN ), EMP_SUM AS ( SELECT OWKEY, CTKEY, MIDSTN, COUNT(DISTINCT EMPNOBRCD) AS EMPCNT FROM ( SELECT OWKEY, CTKEY, MIDSTN, EMPNOBRCD, ROW_NUMBER() OVER ( PARTITION BY OWKEY, CTKEY, MIDSTN, EMPNOBRCD ORDER BY INSERT_DT DESC ) AS RN FROM BASE WHERE EMPNOBRCD IS NOT NULL ) WHERE RN = 1 GROUP BY OWKEY, CTKEY, MIDSTN ), EXPECT_SUM AS ( SELECT PD.OWKEY, PD.CTKEY, CASE ARKEY WHEN 'PA' THEN 'MD01' WHEN 'HA' THEN 'MD02' WHEN 'HB' THEN 'MD03' WHEN 'HC' THEN 'MD04' WHEN 'HD' THEN 'MD05' WHEN 'HE' THEN 'MD06' WHEN 'HF' THEN 'MD07' WHEN 'HG' THEN 'MD08' WHEN 'PB' THEN 'MD09' ELSE '로봇 이형물' END AS MIDSTN, CASE WHEN LC.ARKEY NOT IN ('PA', 'HA', 'HB', 'HC', 'HD', 'HE', 'HF', 'HG', 'PB') THEN '-' ELSE LC.ARKEY END AS ARKEY, COUNT(DISTINCT PD.ICKEY) AS EXICCNT, SUM(PD.EXPCTQTY) AS EXPCTQTY FROM TWORK_INFO_WA_HD WH INNER JOIN TWORK_INFO_OB_HD OH ON WH.OWKEY = OH.OWKEY AND WH.CTKEY = OH.CTKEY AND WH.WAHDKEY = OH.WAHDKEY INNER JOIN TWORK_INFO_PI_DT PD ON OH.OWKEY = PD.OWKEY AND OH.CTKEY = PD.CTKEY AND OH.OBHDKEY = PD.OBHDKEY JOIN TWORK_MST_LC LC ON PD.CTKEY = LC.CTKEY AND PD.LCKEY = LC.LCKEY WHERE 1=1
AND PD.OWKEY = #{owkey}
AND PD.CTKEY = #{ctkey}
AND PD.PIHDKEY = #{pihdkey}
AND LC.ZNKEY IN ('H','P') AND 1 = ( CASE WHEN WH.WKTYPECD = 'RW' THEN (CASE WHEN PD.ROBSORTERICYN = 'N' THEN 1 ELSE 0 END) ELSE 1 END ) GROUP BY PD.OWKEY, PD.CTKEY, LC.ARKEY ), STN_BASE AS ( ( SELECT CASE ARKEY WHEN 'PA' THEN 'MD01' WHEN 'HA' THEN 'MD02' WHEN 'HB' THEN 'MD03' WHEN 'HC' THEN 'MD04' WHEN 'HD' THEN 'MD05' WHEN 'HE' THEN 'MD06' WHEN 'HF' THEN 'MD07' WHEN 'HG' THEN 'MD08' WHEN 'PB' THEN 'MD09' END AS MIDSTN, ARKEY FROM TWORK_MST_AR WHERE 1=1 AND CTKEY = '09' AND ZNKEY IN ('H','P') AND ARKEY IN ('PA', 'HA', 'HB', 'HC', 'HD', 'HE', 'HF', 'HG', 'PB') ) UNION ALL ( SELECT '로봇 이형물', '-') ) SELECT S.MIDSTN, S.ARKEY, P.EXICCNT, P.EXPCTQTY, P.CFICCNT AS CFICCNT, P.DCLFRMQTY AS DCLFRMQTY, CASE WHEN P.EXICCNT = 0 THEN 0 ELSE ROUND(P.CFICCNT / P.EXICCNT * 100, 1) END AS SKUPROC, CASE WHEN P.EXPCTQTY = 0 THEN 0 ELSE ROUND(P.DCLFRMQTY / P.EXPCTQTY * 100, 1) END AS EAPROC, COALESCE(E.EMPCNT, 0) AS EMPCNT, TO_CHAR(P.START_DT, 'YYYY-MM-DD HH24:MI:SS') AS STARTDATE, TO_CHAR(P.END_DT, 'YYYY-MM-DD HH24:MI:SS') AS ENDDATE, LPAD(TRUNC((P.END_DT - P.START_DT) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((P.END_DT - P.START_DT) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((P.END_DT - P.START_DT) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS TIMEDIFF, (END_DT - START_DT) * 24 * 60 * 60 AS TIMEDIFF2 FROM STN_BASE S LEFT JOIN EMP_SUM E ON S.MIDSTN = E.MIDSTN LEFT JOIN ( SELECT COALESCE(S.MIDSTN, '로봇 이형물') AS MIDSTN, COALESCE(S.EXICCNT, 0) AS EXICCNT, COALESCE(S.EXPCTQTY, 0) AS EXPCTQTY, P.CFICCNT, P.DCLFRMQTY, P.START_DT, P.END_DT FROM PROC_SUM P LEFT JOIN EXPECT_SUM S ON P.OWKEY = S.OWKEY AND P.CTKEY = S.CTKEY AND P.MIDSTN = S.MIDSTN ) P ON S.MIDSTN = P.MIDSTN ORDER BY S.MIDSTN

