mapper.sql:
WITH EX AS ( -- 분류계획 SELECT A.OWKEY, A.CTKEY, SUBSTR(B.DASCELLBRCD, 0, 3) STNFAC, -- 셀바코드 (소분류) COUNT(DISTINCT B.OBHDKEY) AS EXORCNT, COUNT(DISTINCT C.ICKEY) AS EXICCNT, -- 상품코드 SUM(C.ORDQTY) AS exordqty-- 주문수량 FROM TWIF_DAS_CLASSIFPLAN_WA A -- 분류계획/웨이브 INNER JOIN TWIF_DAS_CLASSIFPLAN_ORDER B -- 분류계획/주문 ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.WASEQ = B.WASEQ INNER JOIN TWIF_DAS_CLASSIFPLAN_IC C -- 분류계획/상품 ON B.OWKEY = C.OWKEY AND B.CTKEY = C.CTKEY AND B.WASEQ = C.WASEQ AND B.ORDERSEQ = C.ORDERSEQ INNER JOIN TWORK_MST_STNWKCELL SW ON B.CTKEY = SW.CTKEY AND B.DASCELLBRCD = REPLACE(SW.CELLBARCODE, '-', '') WHERE A.IFTYPE = 'S' AND A.IFSTATUS = '90'
AND A.OWKEY = #{owkey}
AND A.CTKEY = #{ctkey}
AND A.WAHDKEY = #{wahdkey}
GROUP BY A.OWKEY, A.CTKEY, SUBSTR(B.DASCELLBRCD, 0, 3) ), PR AS ( -- 처리실적 (중/소 분류) SELECT A.OWKEY, A.CTKEY, SUBSTR(CASE WHEN A.DASDIV = '2' THEN C.OBHDKEY ELSE B.DASCELLBRCD END, 0, 3) STNFAC, -- SUM(CASE WHEN A.IFTYPE = 'R' AND A.DASDIV = '2' THEN 1 ELSE 0 END) AS MIDPRORCNT, COUNT(DISTINCT CASE WHEN A.DASDIV = '3' THEN B.OBHDKEY END) AS SRTPRORCNT, COUNT(DISTINCT CASE WHEN A.DASDIV = '2' THEN C.ICKEY ELSE NULL END) AS MIDPRICCNT, COUNT(DISTINCT CASE WHEN A.DASDIV = '3' THEN C.ICKEY ELSE NULL END) AS SRTPRICCNT, SUM(CASE WHEN A.DASDIV = '2' THEN C.QTY ELSE 0 END) AS MIDCNFRMQTY, -- 중분류처리실적 SUM(CASE WHEN A.DASDIV = '3' THEN C.QTY ELSE 0 END) AS SRTCNFRMQTY, -- 소분류처리실적 MAX(CASE WHEN A.DASDIV = '3' THEN A.INSERTDATE ELSE NULL END) AS SRTMAXCNFRMDATE, TO_DATE(MAX(CASE WHEN A.DASDIV = '3' THEN A.INSERTDATE ELSE NULL END), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(CASE WHEN A.DASDIV = '3' THEN A.INSERTDATE ELSE NULL END), 'YYYYMMDDHH24MISS') AS TIMEDIFF FROM TWIF_DAS_PRCSRSLT_WA A -- 분류처리/웨이브 INNER JOIN TWIF_DAS_PRCSRSLT_ORDER B -- 분류처리/주문 ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.WASEQ = B.WASEQ INNER JOIN TWIF_DAS_PRCSRSLT_IC C -- 분류처리/상품 ON B.OWKEY = C.OWKEY AND B.CTKEY = C.CTKEY AND B.WASEQ = C.WASEQ AND B.ORDERSEQ = C.ORDERSEQ WHERE A.DASDIV IN ('2', '3') AND A.IFTYPE = 'R' AND A.IFSTATUS = '90'
AND A.OWKEY = #{owkey}
AND A.CTKEY = #{ctkey}
AND A.WAHDKEY = #{wahdkey}
GROUP BY A.OWKEY, A.CTKEY, SUBSTR(CASE WHEN A.DASDIV = '2' THEN C.OBHDKEY ELSE B.DASCELLBRCD END, 0, 3) ), TT AS ( -- 분류토트발생수 SELECT WA.OWKEY, WA.CTKEY, 'D' || SUBSTR(ORD.DASCELLBRCD, 2, 2) AS STNFAC, MIN(WA.INSERTDATE) AS SRTMINCNFRMDATE, -- 소분류처리시간 COUNT(DISTINCT ORD.CLASSIFTOTEBRCD) AS CLASSIFTOTEBRCDCNT FROM TWIF_DAS_CLASSIFTOTE_MAPP_WA WA INNER JOIN TWIF_DAS_CLASSIFTOTE_MAPP_ORDER ORD ON WA.WASEQ = ORD.WASEQ WHERE 1 = 1 AND WA.IFTYPE = 'R' AND WA.IFSTATUS = '90'
AND WA.OWKEY = #{owkey}
AND WA.CTKEY = #{ctkey}
AND WA.WAHDKEY = #{wahdkey}
GROUP BY WA.OWKEY, WA.CTKEY, SUBSTR(ORD.DASCELLBRCD, 2, 2) ), EP AS ( -- 작업자 수 SELECT OWKEY, CTKEY, STNFAC, COUNT(DISTINCT EMPNOBRCD) EMPCNT FROM ( SELECT OWKEY, CTKEY, STNFAC, EMPNOBRCD FROM ( SELECT OWKEY, CTKEY, STNFAC, EMPNOBRCD, RANK() OVER (PARTITION BY OWKEY, CTKEY, EMPNOBRCD ORDER BY MAXCNFRMDATE) RNK FROM ( SELECT A.OWKEY, A.CTKEY, SUBSTR(B.DASCELLBRCD, 0, 3) AS STNFAC, -- 셀바코드 C.EMPNOBRCD, MAX(A.INSERTDATE) AS MAXCNFRMDATE FROM TWIF_DAS_PRCSRSLT_WA A -- 분류처리/웨이브 INNER JOIN TWIF_DAS_PRCSRSLT_ORDER B -- 분류처리/주문 ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.WASEQ = B.WASEQ INNER JOIN TWIF_DAS_PRCSRSLT_IC C -- 분류처리/상품 ON B.OWKEY = C.OWKEY AND B.CTKEY = C.CTKEY AND B.WASEQ = C.WASEQ AND B.ORDERSEQ = C.ORDERSEQ WHERE A.DASDIV = '3'
AND A.OWKEY = #{owkey}
AND A.CTKEY = #{ctkey}
AND A.WAHDKEY = #{wahdkey}
GROUP BY A.OWKEY, A.CTKEY, SUBSTR(B.DASCELLBRCD, 0, 3), C.OBHDKEY, C.EMPNOBRCD ) ) WHERE RNK = 1 ) GROUP BY OWKEY, CTKEY, STNFAC ), TS AS ( -- 소분류 스테이션 별 토트박스 규격 정보 SELECT WS.OWKEY, WS.CTKEY, ST.STNFACNO AS STNFAC, WS.CLASSIFSPECCD FROM TWORK_INFO_WA_DAS_STN WS INNER JOIN TWORK_MST_STN ST ON WS.CTKEY = ST.CTKEY AND WS.STNBARCODE = ST.STNBARCODE WHERE 1=1
AND WS.OWKEY = #{owkey}
AND WS.CTKEY = #{ctkey}
AND WS.WAHDKEY = #{wahdkey}
), TM AS ( -- 토트박스 매핑 -- 토트박스 매핑 (웨이브) SELECT A.OWKEY, A.CTKEY, SUBSTR(B.DASCELLBRCD, 0, 3) AS STNFAC, COUNT(DISTINCT B.CLASSIFTOTEBRCD) AS STRCNT FROM TWIF_DAS_CLASSIFTOTE_MAPP_WA A JOIN TWIF_DAS_CLASSIFTOTE_MAPP_ORDER B ON A.WASEQ = B.WASEQ WHERE A.IFTYPE = 'S'
AND A.OWKEY = #{owkey}
AND A.CTKEY = #{ctkey}
AND A.WAHDKEY = #{wahdkey}
GROUP BY A.OWKEY, A.CTKEY, SUBSTR(B.DASCELLBRCD, 0, 3) ), BS AS ( -- 스테이션정보 (베이스) SELECT 'DAISO' AS OWKEY, CTKEY, STNFACNO AS STNFAC FROM TWORK_MST_STN WHERE STNDIVCD = '10' ) SELECT BS.OWKEY, BS.CTKEY, SUBSTR(BS.STNFAC, 2, 2) AS stnfacno, COALESCE(TS.CLASSIFSPECCD, '') AS CLASSIFSPECCD, COALESCE(PR.MIDPRICCNT, 0) AS MIDPRICCNT, COALESCE(PR.MIDCNFRMQTY, 0) AS MIDCNFRMQTY, COALESCE(EX.EXORCNT, 0) AS exobcnt, COALESCE(EX.EXICCNT, 0) AS EXICCNT, COALESCE(EX.exordqty, 0) AS exqty, COALESCE(PR.SRTPRORCNT, 0) AS cfobcnt, COALESCE(PR.SRTPRICCNT, 0) AS cficcnt, COALESCE(PR.SRTCNFRMQTY, 0) AS cfqty, COALESCE(TT.CLASSIFTOTEBRCDCNT, 0) AS cftotcnt, CASE WHEN EX.EXORCNT = 0 THEN 0 ELSE COALESCE(ROUND(PR.SRTPRORCNT / EX.EXORCNT * 100), 0) END AS procob, CASE WHEN EX.exordqty = 0 THEN 0 ELSE COALESCE(ROUND(PR.SRTPRICCNT / EX.EXICCNT * 100), 0) END AS procic, CASE WHEN EX.exordqty = 0 THEN 0 ELSE COALESCE(ROUND(PR.SRTCNFRMQTY / EX.exordqty * 100), 0) END AS procqty , COALESCE(EP.EMPCNT, 0) AS EMPCNT, TO_CHAR(TO_DATE(TT.SRTMINCNFRMDATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS startdate, TO_CHAR(TO_DATE(PR.SRTMAXCNFRMDATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS enddate, -- 소요시간 CASE WHEN PR.TIMEDIFF IS NOT NULL THEN LPAD(TRUNC((PR.TIMEDIFF) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((PR.TIMEDIFF) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((PR.TIMEDIFF) * 24 * 60 * 60, 60))::TEXT, 2, '0') ELSE '' END AS TIMEDIFF, (PR.TIMEDIFF) * 24 * 60 * 60 AS TIMEDIFF2 FROM BS LEFT JOIN EX ON BS.OWKEY = EX.OWKEY AND BS.CTKEY = EX.CTKEY AND BS.STNFAC = EX.STNFAC LEFT JOIN PR ON BS.OWKEY = PR.OWKEY AND BS.CTKEY = PR.CTKEY AND BS.STNFAC = PR.STNFAC LEFT JOIN TT ON BS.OWKEY = TT.OWKEY AND BS.CTKEY = TT.CTKEY AND BS.STNFAC = TT.STNFAC LEFT JOIN TM ON BS.OWKEY = TM.OWKEY AND BS.CTKEY = TM.CTKEY AND BS.STNFAC = TM.STNFAC LEFT JOIN EP ON BS.OWKEY = EP.OWKEY AND BS.CTKEY = EP.CTKEY AND BS.STNFAC = EP.STNFAC LEFT JOIN TS ON BS.OWKEY = TS.OWKEY AND BS.CTKEY = TS.CTKEY AND BS.STNFAC = TS.STNFAC ORDER BY SUBSTR(BS.STNFAC, 2, 2)

