mapper.sql:
SELECT B.DIV, A.EXORDCNT, A.EXOBCNT, A.EXICCNT, A.EXQTY, A.CFORDCNT, A.CFOBCNT, A.CFICCNT, A.CFQTY, A.CFPROC, A.HLDORDCNT, A.HLDOBCNT, A.HLDICCNT, A.HLDQTY, A.URCNT, A.STARTDATE, A.ENDDATE, A.TIMEDIFF, A.TIMEDIFF2 FROM ( ( SELECT OH.OWKEY, OH.CTKEY, OH.WAHDKEY, '포장' AS DIV, COUNT(DISTINCT CASE WHEN OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS EXORDCNT, COUNT(DISTINCT OH.OBHDKEY) AS EXOBCNT, COUNT(DISTINCT OD.ICKEY) AS EXICCNT, SUM(OD.EXPCTQTY) AS EXQTY, COUNT(DISTINCT CASE WHEN (OH.PCKGDATE IS NOT NULL OR NH.OBHDKEY IS NOT NULL) AND OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS CFORDCNT, -- 검수완료주문 COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NOT NULL OR NH.OBHDKEY IS NOT NULL THEN OH.OBHDKEY END) AS CFOBCNT, -- 검수완료 COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NOT NULL OR NH.OBHDKEY IS NOT NULL THEN OD.ICKEY END) AS CFICCNT, -- 포장 대기 품번 SUM(OD.PAKQTY) AS CFQTY, -- 포장 완료 수량 CASE WHEN COUNT(DISTINCT OH.OBHDKEY) = 0 THEN 0 ELSE ROUND((COUNT(DISTINCT OH.OBHDKEY) - COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NULL THEN OH.OBHDKEY END)) / COUNT(DISTINCT OH.OBHDKEY) * 100, 1) END AS CFPROC, -- 진척율(건수) COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'N' AND OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS HLDORDCNT, -- 결품 보류 주문 COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'N' THEN OH.OBHDKEY END) AS HLDOBCNT, -- 결품 보류 릴리즈 COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'N' THEN NH.ICKEY END) AS HLDICCNT, -- 결품 보류 품번 SUM(CASE WHEN NH.CNFRMYN = 'N' THEN COALESCE(NH.CNFRMQTY, 0) ELSE 0 END) AS HLDQTY, -- 결품 보류 수량 COUNT(DISTINCT OH.PCKGURKEY) AS URCNT, -- 포장작업인원 TO_CHAR(TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STARTDATE, TO_CHAR(TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS ENDDATE, LPAD(TRUNC((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS timediff, (TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60 AS TIMEDIFF2 FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.OWKEY = OD.OWKEY AND OH.CTKEY = OD.CTKEY AND OH.OBHDKEY = OD.OBHDKEY LEFT OUTER JOIN ( SELECT NH.OWKEY, NH.CTKEY, NH.OBHDKEY, NH.CNFRMYN, ND.ICKEY, ND.CNFRMQTY FROM TWORK_INFO_OB_NIS_HD NH INNER JOIN TWORK_INFO_OB_NIS_DT ND ON NH.OWKEY = ND.OWKEY AND NH.CTKEY = ND.CTKEY AND NH.OBNISNO = ND.OBNISNO ) NH ON OD.OWKEY = NH.OWKEY AND OD.CTKEY = NH.CTKEY AND OD.OBHDKEY = NH.OBHDKEY AND OD.ICKEY = NH.ICKEY WHERE 1=1
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.WAHDKEY = #{wahdkey}
GROUP BY OH.OWKEY, OH.CTKEY, OH.WAHDKEY ) UNION ( SELECT OH.OWKEY, OH.CTKEY, OH.WAHDKEY, '결품보류 완료' AS DIV, COUNT(DISTINCT CASE WHEN OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS EXORDCNT, /*총 주문 수*/ COUNT(DISTINCT OH.OBHDKEY) AS EXOBCNT, /*총 릴리즈 수*/ COUNT(DISTINCT ND.ICKEY) AS EXICCNT, /*총 상품 수*/ SUM(COALESCE(ND.EXPCTQTY, 0)) AS EXQTY, /*총 예정수량*/ COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'Y' AND OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS CFORDCNT, /*확정 주문 수*/ COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'Y' THEN OH.OBHDKEY END) AS CFOBCNT, /*확정 릴리즈 수*/ COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'Y' THEN ND.ICKEY END) AS CFICCNT, /*확정 상품 수*/ SUM(CASE WHEN NH.CNFRMYN = 'Y' THEN COALESCE(ND.CNFRMQTY, 0) ELSE 0 END) AS CFQTY, /*확정 수량*/ CASE WHEN COUNT(DISTINCT OH.OBHDKEY) = 0 THEN 0 ELSE ROUND(COUNT(DISTINCT CASE WHEN NH.CNFRMYN = 'Y' THEN OH.OBHDKEY END) / COUNT(DISTINCT OH.OBHDKEY) * 100, 1) END AS CFPROC, -- 진척율(건수) COUNT(DISTINCT CASE WHEN NH.CNFRMYN != 'Y' AND OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS HLDORDCNT, /*결품 보류 대기 주문 수*/ COUNT(DISTINCT CASE WHEN NH.CNFRMYN != 'Y' THEN OH.OBHDKEY END) AS HLDOBCNT, /*결품 보류 대기 릴리즈 수*/ COUNT(DISTINCT CASE WHEN NH.CNFRMYN != 'Y' THEN ND.ICKEY END) AS HLDICCNT, /*결품 보류 대기 상품 수*/ SUM(CASE WHEN NH.CNFRMYN != 'Y' THEN COALESCE(ND.CNFRMQTY, 0) ELSE 0 END) AS HLDQTY, /*결품 보류 대기 수량*/ COUNT(DISTINCT NH.CNFRMURKEY) AS URCNT, -- 포장작업인원 TO_CHAR(TO_DATE(MIN(NH.CNFRMDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STARTDATE, TO_CHAR(TO_DATE(MAX(NH.CNFRMDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS ENDDATE, LPAD(TRUNC((TO_DATE(MAX(NH.CNFRMDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(NH.CNFRMDATE), 'YYYYMMDDHH24MISS')) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(NH.CNFRMDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(NH.CNFRMDATE), 'YYYYMMDDHH24MISS')) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(NH.CNFRMDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(NH.CNFRMDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS timediff, (TO_DATE(MAX(NH.CNFRMDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(NH.CNFRMDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60 AS TIMEDIFF2 FROM TWORK_INFO_OB_NIS_HD NH INNER JOIN TWORK_INFO_OB_NIS_DT ND ON NH.OWKEY = ND.OWKEY AND NH.CTKEY = ND.CTKEY AND NH.OBNISNO = ND.OBNISNO LEFT OUTER JOIN TWORK_INFO_OB_HD OH ON NH.OWKEY = OH.OWKEY AND NH.CTKEY = OH.CTKEY AND ( NH.OBHDKEY = OH.OBHDKEY OR NH.REWKOBHDKEY = OH.OBHDKEY ) WHERE 1=1
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.WAHDKEY = #{wahdkey}
GROUP BY OH.OWKEY, OH.CTKEY, OH.WAHDKEY ) ) A RIGHT OUTER JOIN ( SELECT '포장' AS DIV UNION SELECT '결품보류 완료' AS DIV ) B ON A.DIV = B.DIV ORDER BY B.DIV DESC

