mapper.sql:
WITH PROC AS ( SELECT WA.OWKEY , WA.CTKEY , 'Y' AS ROBSORTERICYN , '로봇 투입' AS FLAG , COUNT(DISTINCT ORD.WBLNO) AS CNFRMORDCNT , COUNT(DISTINCT IC.ICKEY) AS CNFRMSKU , SUM(IC.QTY) AS CNFRMQTY , COUNT(DISTINCT IC.EMPNOBRCD) AS CNFRMURCNT , TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') AS STARTDATE , TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') AS ENDDATE , LPAD(TRUNC((TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS timediff , (TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60 AS TIMEDIFF2 FROM TWIF_ROBDAS_PRCSRSLT_WA WA INNER JOIN TWIF_ROBDAS_PRCSRSLT_ORDER ORD ON WA.OWKEY = ORD.OWKEY AND WA.CTKEY = ORD.CTKEY AND WA.WASEQ = ORD.WASEQ INNER JOIN TWIF_ROBDAS_PRCSRSLT_IC IC ON ORD.OWKEY = IC.OWKEY AND ORD.CTKEY = IC.CTKEY AND ORD.WASEQ = IC.WASEQ AND ORD.ORDERSEQ = IC.ORDERSEQ WHERE 1=1 AND WA.IFSTATUS = '90'
AND WA.OWKEY = #{owkey}
AND WA.CTKEY = #{ctkey}
AND WA.WAHDKEY = #{wahdkey}
GROUP BY WA.OWKEY, WA.CTKEY, WA.WAHDKEY UNION SELECT WA.OWKEY , WA.CTKEY , 'N' AS ROBSORTERICYN , '로봇 이형물' AS FLAG , COUNT(DISTINCT ORD.WBLNO) AS CNFRMORDCNT , COUNT(DISTINCT IC.ICKEY) AS CNFRMSKU , SUM(IC.QTY) AS CNFRMQTY , COUNT(DISTINCT IC.EMPNOBRCD) AS CNFRMURCNT , TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') AS STARTDATE , TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') AS ENDDATE , LPAD(TRUNC((TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS timediff , (TO_DATE(MAX(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(WA.IFPRCSDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60 AS timediff2 FROM TWIF_ROBDAS_RSLTXNIS_WA WA INNER JOIN TWIF_ROBDAS_RSLTXNIS_ORDER ORD ON WA.OWKEY = ORD.OWKEY AND WA.CTKEY = ORD.CTKEY AND WA.WASEQ = ORD.WASEQ INNER JOIN TWIF_ROBDAS_RSLTXNIS_IC IC ON ORD.OWKEY = IC.OWKEY AND ORD.CTKEY = IC.CTKEY AND ORD.WASEQ = IC.WASEQ AND ORD.ORDERSEQ = IC.ORDERSEQ WHERE 1=1 AND WA.IFSTATUS = '90' AND ORD.ROBDASRSLTTYPE = '1' -- 이형물 조회
AND WA.OWKEY = #{owkey}
AND WA.CTKEY = #{ctkey}
AND WA.WAHDKEY = #{wahdkey}
GROUP BY WA.CTKEY, WA.OWKEY, WA.WAHDKEY ), EX AS ( SELECT OH.OWKEY, OH.CTKEY, OD.ROBSORTERICYN, COUNT(DISTINCT OD.OBHDKEY) AS EXORDCNT, COUNT(DISTINCT CASE WHEN OD.ROBSORTERICYN = 'N' THEN OD.ICKEY END) AS EXSKU, SUM(OD.EXPCTQTY) AS EXQTY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY WHERE 1=1 AND OH.ORDSEPTYPECD IN ('30', '40')
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.WAHDKEY = #{wahdkey}
GROUP BY OH.OWKEY, OH.CTKEY, OH.WAHDKEY, OD.ROBSORTERICYN ) SELECT BASE.FLAG, EX.EXORDCNT, EX.EXSKU, EX.EXQTY, PROC.CNFRMORDCNT, PROC.CNFRMSKU, PROC.CNFRMQTY, CASE WHEN EX.EXORDCNT = 0 THEN 0 ELSE ROUND(PROC.CNFRMORDCNT / EX.EXORDCNT * 100, 1) END AS PROCOB, CASE WHEN EX.EXQTY = 0 THEN 0 ELSE ROUND(PROC.CNFRMQTY / EX.EXQTY * 100, 1) END AS PROCQTY, PROC.CNFRMURCNT, TO_CHAR(PROC.STARTDATE, 'YYYY-MM-DD HH24:MI:SS') AS STARTDATE, TO_CHAR(PROC.ENDDATE, 'YYYY-MM-DD HH24:MI:SS') AS ENDDATE, PROC.TIMEDIFF, PROC.TIMEDIFF2 FROM EX INNER JOIN PROC ON EX.OWKEY = PROC.OWKEY AND EX.CTKEY = PROC.CTKEY AND EX.ROBSORTERICYN = PROC.ROBSORTERICYN RIGHT OUTER JOIN ( SELECT 'Y' ROBSORTERICYN, '로봇 투입' AS FLAG UNION SELECT 'N' ROBSORTERICYN, '로봇 이형물' AS FLAG ) BASE ON BASE.FLAG = PROC.FLAG AND BASE.ROBSORTERICYN = PROC.ROBSORTERICYN ORDER BY BASE.FLAG DESC, BASE.ROBSORTERICYN

