mapper.sql:
SELECT B.DIV, A.EXORDCNT, A.EXOBCNT, A.EXICCNT, A.EXQTY, A.CFORDCNT, A.CFOBCNT, A.CFICCNT, A.CFQTY, A.CFPROC, A.PCKURCNT, A.STARTDATE, A.ENDDATE, TIMEDIFF, COALESCE(TIMEDIFF2, 0) AS TIMEDIFF2 FROM ( -- (포장 건) SELECT OH.OWKEY, OH.CTKEY, OH.WAHDKEY, '포장' AS DIV, COUNT(DISTINCT CASE WHEN OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS EXORDCNT, COUNT(DISTINCT OH.OBHDKEY) AS EXOBCNT, COUNT(DISTINCT OD.ICKEY) AS EXICCNT, SUM(OD.EXPCTQTY) AS EXQTY, COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NOT NULL AND OH.PREOBHDKEY IS NULL THEN OH.OBHDKEY END) AS CFORDCNT, COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NOT NULL THEN OH.OBHDKEY END) AS CFOBCNT, COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NOT NULL THEN OD.ICKEY END) AS CFICCNT, SUM(CASE WHEN OH.PCKGDATE IS NOT NULL THEN OD.PAKQTY ELSE 0 END) AS CFQTY, CASE WHEN COUNT(DISTINCT OH.OBHDKEY) = 0 THEN 0 ELSE ROUND(COUNT(DISTINCT CASE WHEN OH.PCKGDATE IS NOT NULL THEN OH.OBHDKEY END) / COUNT(DISTINCT OH.OBHDKEY) * 100, 1) END AS CFPROC, COUNT(DISTINCT OH.PCKGURKEY) PCKURCNT, TO_CHAR(TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STARTDATE, TO_CHAR(TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS ENDDATE, LPAD(TRUNC((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS TIMEDIFF, (TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60 AS timediff2 FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY WHERE 1=1
AND OH.OWKEY = #{owkey}
AND OH.CTKEY = #{ctkey}
AND OH.WAHDKEY = #{wahdkey}
GROUP BY OH.OWKEY, OH.CTKEY, OH.WAHDKEY UNION -- (미출 건) SELECT A.OWKEY, A.CTKEY, A.WAHDKEY, '미출' AS DIV, COUNT(DISTINCT CASE WHEN OH.PREOBHDKEY IS NULL THEN B.OBHDKEY END) AS EXORDCNT, COUNT(DISTINCT B.OBHDKEY) AS EXOBCNT, COUNT(DISTINCT C.ICKEY) AS EXICCNT, SUM(C.QTY) AS EXQTY, COUNT(DISTINCT CASE WHEN OH.OBCNFRMDATE IS NOT NULL AND OH.PREOBHDKEY IS NULL THEN B.OBHDKEY END) AS CFORDCNT, COUNT(DISTINCT CASE WHEN OH.OBCNFRMDATE IS NOT NULL THEN B.OBHDKEY END) AS CFOBCNT, COUNT(DISTINCT CASE WHEN OH.OBCNFRMDATE IS NOT NULL THEN C.ICKEY END) AS CFICCNT, SUM(CASE WHEN OH.OBCNFRMDATE IS NOT NULL THEN C.QTY - OD.NISQTY ELSE 0 END) AS CFQTY, CASE WHEN COUNT(DISTINCT B.OBHDKEY) = 0 THEN 0 ELSE ROUND(COUNT(DISTINCT CASE WHEN OH.OBCNFRMDATE IS NOT NULL THEN B.OBHDKEY END) / COUNT(DISTINCT B.OBHDKEY) * 100, 1) END AS CFPROC, COUNT(DISTINCT OH.PCKGURKEY) PCKURCNT, TO_CHAR(TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STARTDATE, TO_CHAR(TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS ENDDATE, LPAD(TRUNC((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24)::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60, 60))::TEXT, 2, '0') || ':' || LPAD(TRUNC(MOD((TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60, 60))::TEXT, 2, '0') AS TIMEDIFF, (TO_DATE(MAX(OH.PCKGDATE), 'YYYYMMDDHH24MISS') - TO_DATE(MIN(OH.PCKGDATE), 'YYYYMMDDHH24MISS')) * 24 * 60 * 60 AS timediff2 FROM TWIF_ROBDAS_RSLTXNIS_WA A INNER JOIN TWIF_ROBDAS_RSLTXNIS_ORDER B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.WASEQ = B.WASEQ INNER JOIN TWIF_ROBDAS_RSLTXNIS_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.WASEQ = C.WASEQ AND B.ORDERSEQ = C.ORDERSEQ INNER JOIN TWORK_INFO_OB_HD OH ON B.CTKEY = OH.CTKEY AND B.OWKEY = OH.OWKEY AND B.OBHDKEY = OH.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY AND C.ICKEY = OD.ICKEY WHERE B.ROBDASRSLTTYPE = '2' AND A.IFTYPE = 'R'
AND A.OWKEY = #{owkey}
AND A.CTKEY = #{ctkey}
AND A.WAHDKEY = #{wahdkey}
GROUP BY A.OWKEY, A.CTKEY, A.WAHDKEY ) A RIGHT OUTER JOIN ( SELECT '포장' AS DIV UNION SELECT '미출' AS DIV ) B ON A.DIV = B.DIV ORDER BY B.DIV DESC
